"""
Step ID: step04
Step Name: statistical_comparisons_between_domains
RQ: results/ch7/7.6.3
Generated: 2026-01-09

PURPOSE:
Test pairwise difference between What and Where domain ICC estimates and compute effect size.
MODIFIED: Only 1 comparison (What vs Where), not 3 (When domain excluded).
CRITICAL: Decision D068 compliance - dual p-values (uncorrected + bonferroni + fdr).

EXPECTED INPUTS:
  - results/ch7/7.6.3/data/step03_bootstrap_distributions.csv
    Columns: ['domain', 'bootstrap_iteration', 'icc_bootstrap']
    Expected rows: 2000 (1000 iterations x 2 domains)
  - results/ch7/7.6.3/data/step02_icc_estimates.csv
    Columns: ['domain', 'icc_value', 'variance_between', 'variance_total']
    Expected rows: 2

EXPECTED OUTPUTS:
  - results/ch7/7.6.3/data/step04_pairwise_comparisons.csv
    Columns: ['comparison', 'diff_mean', 'diff_ci_lower', 'diff_ci_upper', 'cohens_d',
              'p_uncorrected', 'p_bonferroni', 'p_fdr']
    Expected rows: 1 (What-Where comparison only)

VALIDATION CRITERIA:
  - Exactly 1 pairwise comparison (What-Where)
  - BOTH uncorrected AND corrected p-values present (Decision D068)
  - p_bonferroni >= p_uncorrected (mathematical constraint)
  - p_bonferroni = p_uncorrected (Bonferroni factor = 1 for single test)
  - p_fdr = p_uncorrected (FDR = uncorrected for single test)
  - Effect size (Cohen's d) in reasonable range [-3, 3]
  - All p-values in [0, 1]

g_code REASONING:
- Approach: Bootstrap difference distribution for What - Where ICC values
- Why this approach: Non-parametric test appropriate for ICC comparison
- Data flow: Bootstrap distributions -> Difference distribution -> CI + p-value + Cohen's d
- Expected performance: <1 second
- CRITICAL: Bonferroni factor = 1 (single comparison), so p_bonferroni = p_uncorrected

IMPLEMENTATION NOTES:
- Analysis tool: Manual bootstrap difference calculation + tools.analysis_stats.compute_effect_sizes
- Validation tool: validate_contrasts_dual_pvalues from tools.validation
- Decision D068: Report p_uncorrected, p_bonferroni, p_fdr
- Single test: All three p-values will be identical (no correction needed)
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy import stats

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import tools
from tools.analysis_stats import compute_effect_sizes
from tools.validation import validate_contrasts_dual_pvalues

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step04_statistical_comparisons.log"
OUTPUT_FILE = RQ_DIR / "data" / "step04_pairwise_comparisons.csv"

# Input files
INPUT_BOOT_DIST = RQ_DIR / "data" / "step03_bootstrap_distributions.csv"
INPUT_ICC = RQ_DIR / "data" / "step02_icc_estimates.csv"

# Statistical parameters
ALPHA = 0.05
N_COMPARISONS = 1  # MODIFIED: Only What-Where (When excluded)

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 04: Statistical Comparisons Between Domains")
        log(f"[MODIFIED] Single comparison only (What-Where), When domain excluded")

        # =========================================================================
        # STEP 1: Load Data
        # =========================================================================

        log(f"[LOAD] Reading bootstrap distributions...")
        df_boot = pd.read_csv(INPUT_BOOT_DIST)
        log(f"[LOADED] {len(df_boot)} rows")

        log(f"[LOAD] Reading ICC estimates...")
        df_icc = pd.read_csv(INPUT_ICC)
        log(f"[LOADED] {len(df_icc)} rows")

        # =========================================================================
        # STEP 2: Compute Bootstrap Difference Distribution (What - Where)
        # =========================================================================
        # For each bootstrap iteration, compute ICC_what - ICC_where
        # This gives distribution of differences under resampling

        log(f"[COMPUTE] Calculating bootstrap difference distribution...")

        # Pivot bootstrap distributions to wide format
        df_boot_pivot = df_boot.pivot(
            index='bootstrap_iteration',
            columns='domain',
            values='icc_bootstrap'
        )

        # Compute differences for each bootstrap sample
        diff_boot = df_boot_pivot['What'] - df_boot_pivot['Where']

        log(f"[INFO] Bootstrap differences calculated: {len(diff_boot)} samples")

        # =========================================================================
        # STEP 3: Calculate Difference Statistics
        # =========================================================================

        # Mean difference
        diff_mean = diff_boot.mean()

        # 95% CI for difference (percentile method)
        ci_lower = np.percentile(diff_boot, 2.5)
        ci_upper = np.percentile(diff_boot, 97.5)

        log(f"[DIFFERENCE] Mean: {diff_mean:.4f}")
        log(f"[DIFFERENCE] 95% CI: [{ci_lower:.4f}, {ci_upper:.4f}]")

        # =========================================================================
        # STEP 4: Calculate P-Value (Two-Tailed Test)
        # =========================================================================
        # H0: ICC_what = ICC_where (difference = 0)
        # P-value: Proportion of bootstrap samples with |diff| >= |observed_diff|

        # Observed difference
        icc_what = df_icc[df_icc['domain'] == 'What']['icc_value'].values[0]
        icc_where = df_icc[df_icc['domain'] == 'Where']['icc_value'].values[0]
        diff_observed = icc_what - icc_where

        log(f"[OBSERVED] ICC_what = {icc_what:.4f}, ICC_where = {icc_where:.4f}")
        log(f"[OBSERVED] Difference = {diff_observed:.4f}")

        # Two-tailed p-value
        p_uncorrected = np.mean(np.abs(diff_boot) >= np.abs(diff_observed))

        log(f"[P-VALUE] Uncorrected: {p_uncorrected:.4f}")

        # =========================================================================
        # STEP 5: Multiple Comparison Correction (Decision D068)
        # =========================================================================
        # CRITICAL: Single test, so Bonferroni and FDR = uncorrected
        # Bonferroni correction: p * n_tests (but n_tests = 1)
        # FDR correction: Not applicable for single test

        p_bonferroni = min(p_uncorrected * N_COMPARISONS, 1.0)
        p_fdr = p_uncorrected  # FDR = uncorrected for single test

        log(f"[P-VALUE] Bonferroni (n=1): {p_bonferroni:.4f}")
        log(f"[P-VALUE] FDR (n=1): {p_fdr:.4f}")
        log(f"[INFO] All p-values identical (single test, no correction needed)")

        # =========================================================================
        # STEP 6: Calculate Effect Size (Cohen's d)
        # =========================================================================
        # Cohen's d for ICC comparison: mean_diff / pooled_SD

        # Get What and Where bootstrap samples
        what_boot = df_boot[df_boot['domain'] == 'What']['icc_bootstrap'].values
        where_boot = df_boot[df_boot['domain'] == 'Where']['icc_bootstrap'].values

        # Compute effect size using tools.analysis_stats
        effect_size_result = compute_effect_sizes(
            group1=what_boot,
            group2=where_boot,
            test_type='cohens_d'
        )

        cohens_d = effect_size_result['cohens_d']

        log(f"[EFFECT SIZE] Cohen's d: {cohens_d:.4f}")

        # =========================================================================
        # STEP 7: Create Results DataFrame
        # =========================================================================

        comparison_results = [{
            'comparison': 'What-Where',
            'diff_mean': diff_mean,
            'diff_ci_lower': ci_lower,
            'diff_ci_upper': ci_upper,
            'cohens_d': cohens_d,
            'p_uncorrected': p_uncorrected,
            'p_bonferroni': p_bonferroni,
            'p_fdr': p_fdr
        }]

        df_comparisons = pd.DataFrame(comparison_results)

        log(f"[CREATED] Pairwise comparisons table: {len(df_comparisons)} row")

        # =========================================================================
        # STEP 8: Validate Decision D068 Compliance
        # =========================================================================

        log(f"[VALIDATE] Checking Decision D068 compliance...")

        validation_result = validate_contrasts_dual_pvalues(
            contrasts_df=df_comparisons,
            required_comparisons=['What-Where']
        )

        if not validation_result.get('valid', False):
            log(f"[ERROR] D068 validation failed: {validation_result}")
            sys.exit(1)
        else:
            log(f"[PASS] Decision D068 compliance verified")
            log(f"[PASS] All required comparisons present")
            log(f"[PASS] Dual p-values (uncorrected + bonferroni + fdr) present")

        # Validate mathematical constraints
        if df_comparisons['p_bonferroni'].values[0] < df_comparisons['p_uncorrected'].values[0]:
            log(f"[ERROR] p_bonferroni < p_uncorrected (impossible)")
            sys.exit(1)
        else:
            log(f"[PASS] p_bonferroni >= p_uncorrected")

        # Validate p-values in [0, 1]
        for p_col in ['p_uncorrected', 'p_bonferroni', 'p_fdr']:
            p_val = df_comparisons[p_col].values[0]
            if p_val < 0 or p_val > 1:
                log(f"[ERROR] {p_col} = {p_val} outside [0, 1]")
                sys.exit(1)

        log(f"[PASS] All p-values in [0, 1]")

        # Validate effect size range
        if abs(cohens_d) > 3:
            log(f"[WARN] Large effect size |d| = {abs(cohens_d):.4f} > 3")
        else:
            log(f"[PASS] Effect size in reasonable range")

        # =========================================================================
        # STEP 9: Save Results
        # =========================================================================

        log(f"[SAVE] Writing pairwise comparisons...")
        df_comparisons.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_FILE} ({len(df_comparisons)} row)")

        log(f"[SUCCESS] Step 04 complete")
        log(f"[SUMMARY] What-Where comparison: diff={diff_mean:.4f}, p={p_uncorrected:.4f}, d={cohens_d:.4f}")
        log(f"[NEXT] Proceed to step05 (outlier analysis)")

        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
